@mixin grid(
  $breakpoints: $grid-breakpoints,
  $grid-gutter: $grid-gutter,
  $condensed-gutter: $grid-gutter--condensed
) {
  .#{$prefix}--grid {
    @include -make-container($breakpoints);
  }

  @include largest-breakpoint($breakpoints) {
    .#{$prefix}--grid--full-width {
      max-inline-size: 100%;
    }
  }

  .#{$prefix}--row {
    @include make-row();
  }

  .#{$prefix}--row-padding [class*='#{$prefix}--col'],
  .#{$prefix}--col-padding {
    padding-block: $grid-gutter * 0.5;
  }

  .#{$prefix}--grid--condensed [class*='#{$prefix}--col'] {
    padding-block: $condensed-gutter * 0.5;
  }

  @include -make-grid-columns($breakpoints, $grid-gutter);
  @include -no-gutter();
  @include -hang($grid-gutter);
}

@mixin emit-layout-tokens-to-shadow-host($host-selector) {
  @each $group, $properties in $layout-tokens {
    @each $property, $steps in $properties {
      @each $step, $value in $steps {
        :host(#{$host-selector}[#{$group}='#{$step}']) {
          @include custom-property.declaration(
            'layout-#{$group}-#{$property}-context',
            custom-property.get-var(
              'layout-#{$group}-#{$property}-#{$step}',
              $value
            )
          );
          @include custom-property.declaration(
            'layout-#{$group}-#{$property}',
            custom-property.get-var('layout-#{$group}-#{$property}-context')
          );
        }
      }
    }
  }
}

@each $group, $properties in $layout-tokens {
  @each $property, $steps in $properties {
    @each $step, $value in $steps {
      :host(#{$host-selector}[#{$group}='#{$step}']) {
        @include custom-property.declaration(
          'layout-#{$group}-#{$property}-context',
          custom-property.get-var(
            'layout-#{$group}-#{$property}-#{$step}',
            $value
          )
        );
        @include custom-property.declaration(
          'layout-#{$group}-#{$property}',
          custom-property.get-var('layout-#{$group}-#{$property}-context')
        );
      }
    }
  }
}

@each $group in $-components {
  @each $key, $value in $group {
    @if meta.type-of($value) == map {
      $fallback: map.get($value, fallback);
      $theme-values: map.get($value, values);

      @each $theme-value in $theme-values {
        $value: map.get($theme-value, value);

        @if theme.matches(map.get($theme-value, theme), $theme) and
          meta.type-of($value) ==
          color
        {
          @include custom-property.declaration($key, $value);
        }
      }
    } @else if meta.type-of($value) == color {
      @include custom-property.declaration($key, $value);
    }
  }
}

@mixin aspect-ratio($aspect-ratios: $aspect-ratios) {
  .#{$prefix}--aspect-ratio {
    position: relative;
  }

  .#{$prefix}--aspect-ratio::before {
    block-size: 0;
    content: '';
    // float: inline-start is not supported yet
    // https://caniuse.com/mdn-css_properties_float_flow_relative_values
    // stylelint-disable-next-line csstools/use-logical
    float: left;
    inline-size: 1px;
    margin-inline-start: -1px;
  }

  .#{$prefix}--aspect-ratio::after {
    display: table;
    clear: both;
    content: '';
  }

  @each $aspect-ratio in $aspect-ratios {
    $width: list.nth($aspect-ratio, 1);
    $height: list.nth($aspect-ratio, 2);

    .#{$prefix}--aspect-ratio--#{$width}x#{$height}::before {
      padding-block-start: math.percentage(math.div($height, $width));
    }
  }
}

@mixin badge-indicator {
  .#{$prefix}--badge-indicator {
    @include type.type-style('helper-text-01');

    position: absolute;
    display: flex;
    padding: 0 $spacing-02 $spacing-01;
    border-radius: 100px;
    background: $support-error;
    color: $text-on-color;

    inset-block-start: 0;
    inset-inline-end: 0;

    margin-block-start: $spacing-03;
    margin-inline-end: $spacing-03;

    max-block-size: $spacing-05;
    min-block-size: $spacing-03;
    min-inline-size: $spacing-03;
  }

  .#{$prefix}--badge-indicator--count {
    margin-block-start: $spacing-02;
    margin-inline-end: $spacing-02;
  }
}

@mixin sticky-header(
  $min-width: false,
  $max-width: 100%,
  $max-height: convert.to-rem(300px)
) {
  .#{$prefix}--data-table--max-width {
    max-inline-size: $max-width;
  }

  .#{$prefix}--data-table--sticky-header {
    max-block-size: $max-height;

    @if $min-width {
      th:not(.#{$prefix}--table-column-checkbox):not(
          .#{$prefix}--table-column-menu
        ):not(.#{$prefix}--table-expand):not(.#{$prefix}--table-column-icon),
      td:not(.#{$prefix}--table-column-checkbox):not(
          .#{$prefix}--table-column-menu
        ):not(.#{$prefix}--table-expand):not(.#{$prefix}--table-column-icon) {
        min-inline-size: $min-width;
      }
    }
  }
}

@if not(
  enabled('enable-experimental-focus-wrap-without-sentinels') or
    $enable-experimental-focus-wrap-without-sentinels or
    enabled('enable-focus-wrap-without-sentinels') or
    $enable-focus-wrap-without-sentinels or
    enabled('enable-dialog-element') or
    $enable-dialog-element
)
{
  .#{$prefix}--modal--enable-presence {
    @include modal-container-animations($has-presence: true);
  }

  :not(.#{$prefix}--modal--enable-presence) {
    @include modal-container-animations(
      $has-presence: enabled('enable-presence') or $enable-presence
    );
  }
}

@if not(
  enabled('enable-experimental-focus-wrap-without-sentinels') or
    $enable-experimental-focus-wrap-without-sentinels or
    enabled('enable-focus-wrap-without-sentinels') or
    $enable-focus-wrap-without-sentinels or
    enabled('enable-dialog-element') or
    $enable-dialog-element
)
{
  position: fixed;
  z-index: z('modal');
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: $overlay;
  block-size: 100vh;
  content: '';
  inline-size: 100vw;
  inset-block-start: 0;
  inset-inline-start: 0;

  &.#{$prefix}--modal--enable-presence {
    @include modal-animations($has-presence: true);
  }

  &:not(.#{$prefix}--modal--enable-presence) {
    @include modal-animations(
      $has-presence: enabled('enable-presence') or $enable-presence
    );
  }
}

li {
  float: #{$global-left};

  font-size: $breadcrumbs-item-font-size;
  color: $breadcrumbs-item-color-current;
  cursor: default;

  @if $breadcrumbs-item-uppercase {
    text-transform: uppercase;
  }

  @if $breadcrumbs-item-separator {
    // Need to escape the backslash
    $separator: if($global-text-direction == 'ltr', $breadcrumbs-item-separator-item, $breadcrumbs-item-separator-item-rtl);

    &:not(:last-child) {
      &::after {
        position: relative;
        margin: 0 $breadcrumbs-item-margin;
        opacity: 1;
        content: $separator;
        color: $breadcrumbs-item-separator-color;
      }
    }
  }
  @else {
    margin-#{$global-right}: $breadcrumbs-item-margin;
  }
}

#{$child-selector} {
  margin: 0;
  margin-#{$global-right}: $spacing;
  margin-bottom: $spacing;
  font-size: map-get($button-sizes, default);

  @if $global-flexbox {
    flex: 0 0 auto;
  }

  &:last-child {
    margin-#{$global-right}: 0;
  }

  @if not $buttongroup-radius-on-each {
    border-radius: 0;

    &:first-child {
      border-top-#{$global-left}-radius: $button-radius;
      border-bottom-#{$global-left}-radius: $button-radius;
    }

    &:last-child {
      border-top-#{$global-right}-radius: $button-radius;
      border-bottom-#{$global-right}-radius: $button-radius;
    }
  }
}

@else {
  // One child
  &:first-child {
    &:last-child {
      width: calc(100% - #{$spacing});
    }
  }

  // Two or more childreen
  @for $i from 2 through $buttongroup-expand-max {
    &:first-child:nth-last-child(#{$i}) {
      &, &:first-child:nth-last-child(#{$i}) ~ #{$selector} {
        display: inline-block;
        width: calc(#{percentage(divide(1, $i))} - #{$spacing});
        margin-#{$global-right}: $spacing;

        &:last-child {
          margin-#{$global-right}: $spacing * -$buttongroup-expand-max;
        }
      }
    }
  }
}

@mixin button-group-unstack(
  $selector: $buttongroup-child-selector
) {
  #{$selector} {
    @if $global-flexbox {
      flex: 0 0 auto;
    }
    @else {
      width: auto;
    }
    margin-bottom: 0;

    @if not $buttongroup-radius-on-each {
      &:first-child {
        border-top-#{$global-left}-radius: $global-radius;
        border-top-#{$global-right}-radius: 0;
        border-bottom-#{$global-left}-radius: $global-radius;
      }

      &:last-child {
        border-top-#{$global-right}-radius: $global-radius;
        border-bottom-#{$global-right}-radius: $global-radius;
        border-bottom-#{$global-left}-radius: 0;
      }
    }

  }
}

&#{$base-selector} {
  // Do not generate button base styles for the default filling
  @if($button-fill != $filling) {
    #{$buttongroup-child-selector} {
      @include button-fill($filling);
      @include button-fill-style($filling);
    }
  }

  @each $name, $color in $button-palette {
    @if($button-fill != $filling) {
      $individual-selector: ' #{$buttongroup-child-selector}.#{"" + $name}';
      &.#{"" + $name} #{$buttongroup-child-selector}, &#{$individual-selector} {
        @include button-fill-style($filling, $color, auto, auto);
      }
    }
    @else {
      &.#{"" + $name} #{$buttongroup-child-selector} {
        @include button-fill-style($filling, $color, auto, auto);
      }
    }
  }
}

@mixin button-base {
  display: inline-block;
  vertical-align: middle;
  margin: $button-margin;
  border: $button-border;
  border-radius: $button-radius;
  transition: $button-transition;
  font-family: $button-font-family;
  font-size: map-get($button-sizes, default);
  font-weight: $button-font-weight;
  -webkit-appearance: none; // sass-lint:disable-line no-vendor-prefixes
  line-height: 1;
  text-align: center;
  cursor: pointer;

  @if (type-of($button-padding) == 'map') {
    @each $size, $padding in $button-padding {
      @include breakpoint($size) {
        padding: $padding;
      }
    }
  }
  @else {
    padding: $button-padding;
  }

  @include disable-mouse-outline;
}

@mixin zf-drilldown-left-right-arrows {
  .is-drilldown-submenu-parent > a {
    position: relative;

    &::after {
      @include css-triangle($drilldown-arrow-size, $drilldown-arrow-color, $global-right);
      position: absolute;
      top: 50%;
      margin-top: -1 * $drilldown-arrow-size;
      #{$global-right}: 1rem;
    }
  }

  &.align-left .is-drilldown-submenu-parent > a::after {
    @include css-triangle($dropdownmenu-arrow-size, $dropdownmenu-arrow-color, right);
    right: 1rem;
    left: auto;
  }

  &.align-right .is-drilldown-submenu-parent > a::after {
    @include css-triangle($dropdownmenu-arrow-size, $dropdownmenu-arrow-color, left);
    right: auto;
    left: 1rem;
  }

}

@function xy-cell-offset(
  $n,
  $gutters: $grid-margin-gutters,
  $gutter-type: margin,
  $breakpoint: null
) {
  $breakpoint: -zf-current-breakpoint($breakpoint, $default: $-zf-zero-breakpoint);
  $size: xy-cell-size($n);

  $offset: $size;
  @if ($gutter-type == 'margin') {
    // Make sure that 0 is translated in 0rem for calc()
    $gutter: rem-calc(xy-cell-gutters($gutters, $breakpoint));
    @if $gutter == 0 {
      // sass-lint:disable zero-unit
      $gutter: 0rem;
    }
    $offset: if($gutter == 0, $size, calc(#{$size} + #{$gutter} / 2));
  }
  @return $offset;
}

@each $filling in (solid hollow clear) {
  $base-selector: if($button-fill == $filling, null, '.#{$filling}');

  &#{$base-selector} {
    // Do not generate button base styles for the default filling
    @if($button-fill != $filling) {
      #{$buttongroup-child-selector} {
        @include button-fill($filling);
        @include button-fill-style($filling);
      }
    }

    @each $name, $color in $button-palette {
      @if($button-fill != $filling) {
        $individual-selector: ' #{$buttongroup-child-selector}.#{"" + $name}';
        &.#{"" + $name} #{$buttongroup-child-selector}, &#{$individual-selector} {
          @include button-fill-style($filling, $color, auto, auto);
        }
      }
      @else {
        &.#{"" + $name} #{$buttongroup-child-selector} {
          @include button-fill-style($filling, $color, auto, auto);
        }
      }
    }
  }

}

@if $dir == horizontal {
  > li.opens-left { // sass-lint:disable-line no-qualifying-elements
    > .is-dropdown-submenu {
      top: 100%;
      right: 0;
      left: auto;
    }
  }

  > li.opens-right { // sass-lint:disable-line no-qualifying-elements
    > .is-dropdown-submenu {
      top: 100%;
      right: auto;
      left: 0;
    }
  }

  @if $dropdownmenu-arrows {
    > li.is-dropdown-submenu-parent > a { // sass-lint:disable-line no-qualifying-elements
      position: relative;
      padding-#{$global-right}: $dropdownmenu-arrow-padding;
    }

    > li.is-dropdown-submenu-parent > a::after { // sass-lint:disable-line no-qualifying-elements
      @include css-triangle($dropdownmenu-arrow-size, $dropdownmenu-arrow-color, down);
      #{$global-right}: 5px;
      #{$global-left}: auto;
      margin-top: -1 * ($dropdownmenu-arrow-size * 0.5);
    }
  }
}

@each $size in $breakpoint-classes {
  @include breakpoint($size) {
    @if $size != $-zf-zero-breakpoint {
      .#{$size} {
        @each $prop in (margin, padding) {
          // All Sides
          &-#{$prop}-#{$spacer} {
            @if ($prop == margin) {
              margin: $spacer * $global-margin !important;
            }
            @else if ($prop == padding) {
              padding: $spacer * $global-padding !important;
            }
          }

          @each $dir in (top, right, bottom, left, horizontal, vertical) {
            // Top Side
            &-#{$prop}-#{$dir}-#{$spacer} {
              @if ($prop == margin) {
                @include margin-direction($dir, $spacer);
              }
              @else if ($prop == padding) {
                @include padding-direction($dir, $spacer);
              }
            }
          }
        }
      }
    }
  }
}
